proof fn phi_1_lemma_specializes_any_n_without_constraint(
    spec: TempPred<ClusterState>, vrs: VReplicaSetView, cluster: Cluster, controller_id: int
)
    requires
        spec.entails(always(
            lift_state(Cluster::pending_req_in_flight_or_resp_in_flight_at_reconcile_state(
                controller_id,
                vrs.object_ref(),
                unwrap_local_state_closure(
                    |s: VReplicaSetReconcileState| s.reconcile_step.is_AfterCreatePod()
                )
            )))),
    ensures
        spec.entails(always(
            lift_state(Cluster::pending_req_in_flight_or_resp_in_flight_at_reconcile_state(
                controller_id,
                vrs.object_ref(),
                at_step_closure(VReplicaSetRecStepView::AfterCreatePod(0))
            )))),
        spec.entails(always(
            lift_state(Cluster::pending_req_in_flight_or_resp_in_flight_at_reconcile_state(
                controller_id,
                vrs.object_ref(),
                at_step_closure(VReplicaSetRecStepView::AfterCreatePod(999999))
            )))),
{
    lemma_from_pending_req_in_flight_or_resp_in_flight_at_all_create_to_create_n(spec, vrs, cluster, controller_id, 0);
    lemma_from_pending_req_in_flight_or_resp_in_flight_at_all_create_to_create_n(spec, vrs, cluster, controller_id, 999999);
}

